import{_ as t,o as d,c as o,ag as a}from"./chunks/framework.HG0H2VLS.js";const u=JSON.parse('{"title":"AudioPlayer — Figma Notes","description":"","frontmatter":{},"headers":[],"relativePath":"public/demos/src/components/AudioPlayer/AudioPlayer.figma-notes.md","filePath":"public/demos/src/components/AudioPlayer/AudioPlayer.figma-notes.md"}'),i={name:"public/demos/src/components/AudioPlayer/AudioPlayer.figma-notes.md"};function r(c,e,n,s,l,p){return d(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="audioplayer-—-figma-notes" tabindex="-1">AudioPlayer — Figma Notes <a class="header-anchor" href="#audioplayer-—-figma-notes" aria-label="Permalink to &quot;AudioPlayer — Figma Notes&quot;">​</a></h1><h2 id="figma-node" tabindex="-1">Figma Node <a class="header-anchor" href="#figma-node" aria-label="Permalink to &quot;Figma Node&quot;">​</a></h2><ul><li>File key: <code>Lus07xi8pPXLN87sQIyrEt</code> (Affino AI — Design System)</li><li>Parent frame: <code>3055:5458</code> &quot;Article Audio Player&quot;</li><li>Variants (Tier=Component):<table tabindex="0"><thead><tr><th>Node ID</th><th>Type</th><th>Device</th></tr></thead><tbody><tr><td>3055:5457</td><td>Compact Inline Bar</td><td>Desktop</td></tr><tr><td>3055:5455</td><td>Compact Inline Bar</td><td>Mobile</td></tr><tr><td>3055:5453</td><td>Card with waveform</td><td>Desktop</td></tr><tr><td>3055:5454</td><td>Card with waveform</td><td>Mobile</td></tr><tr><td>3055:5456</td><td>Sticky Mini Player</td><td>Desktop</td></tr><tr><td>3055:5452</td><td>Sticky Mini Player</td><td>Mobile</td></tr></tbody></table></li></ul><h2 id="variant-×-device-matrix" tabindex="-1">Variant × Device Matrix <a class="header-anchor" href="#variant-×-device-matrix" aria-label="Permalink to &quot;Variant × Device Matrix&quot;">​</a></h2><p>Device=Mobile is implemented as <code>@media (max-width: 767px)</code> — never a modifier class.</p><table tabindex="0"><thead><tr><th>Type</th><th>Modifier</th><th>Desktop</th><th>Mobile deltas</th></tr></thead><tbody><tr><td>Compact Inline Bar</td><td><code>--compact</code></td><td>pill, <code>px 12 / py 8</code>, gap 12, play 40 / icon 20; current-time <code>fixed-xs</code> medium, duration <code>fixed-xs</code> regular</td><td>gap 8, padding 8 all; current-time <code>fixed-xxs</code>, duration <code>fixed-sm</code></td></tr><tr><td>Card with waveform</td><td><code>--card</code></td><td><code>radius-lg</code>, padding 24, <code>shadow-card</code>; heading <code>fixed-md</code>; play 56 / icon 24; waveform h48 gap16</td><td>padding 16; heading <code>fixed-sm</code>; play 48 / icon 20; waveform gap 12</td></tr><tr><td>Sticky Mini Player</td><td><code>--mini</code></td><td><code>radius-lg</code>, <code>px 16 / py 12</code>, single row (play · text · scrubber · time · download); play 40 / icon 20</td><td>two rows <code>[play · text · download]</code> / <code>[scrubber · time]</code>, flex-col gap 8, padding 12; download 32</td></tr></tbody></table><p>All three share <code>max-width: --ai-size-11</code> (768px) and shrink to fill narrower screens (Figma mobile frame = <code>--ai-size-6</code> 320px).</p><h2 id="interaction" tabindex="-1">Interaction <a class="header-anchor" href="#interaction" aria-label="Permalink to &quot;Interaction&quot;">​</a></h2><p>No interaction-state <em>variants</em> exist in Figma (axes are Type × Device only). Behaviour (JS, <code>AudioPlayer.js</code>), confirmed against the validated prototypes:</p><ul><li>Play/pause: toggles <code>.is-playing</code> on the root → swaps <code>--play</code>/<code>--pause</code> icon; <code>aria-pressed</code> synced.</li><li>Scrubber / waveform: click-to-seek (<code>[data-ap-scrubber]</code> / <code>[data-ap-waveform]</code>).</li><li>Duration button: toggles between total time and <code>-remaining</code>.</li><li>Download: no-op — <strong>backend TODO</strong> (see below).</li><li>Waveform bars are generated deterministically from the track width (no <code>Math.random</code>, stable) — the per-bar heights in Figma are amplitude data, not tokens.</li></ul><h2 id="css-class-mapping" tabindex="-1">CSS Class Mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS Class Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma layer</th><th>CSS class</th></tr></thead><tbody><tr><td>Article Audio Player (root)</td><td><code>.audio-player</code> + <code>--compact</code> / <code>--card</code> / <code>--mini</code></td></tr><tr><td>Button - Play / pause</td><td><code>.audio-player__play</code> (icon <code>.audio-player__icon--play/--pause</code>)</td></tr><tr><td>Slider - Seek (thin)</td><td><code>.audio-player__scrubber</code> + <code>.audio-player__scrubber-fill</code></td></tr><tr><td>Slider - Seek (waveform)</td><td><code>.audio-player__waveform</code> + <code>.audio-player__bar</code> (<code>.is-played</code>)</td></tr><tr><td>current time</td><td><code>.audio-player__time</code></td></tr><tr><td>&quot;/&quot; separator</td><td><code>.audio-player__time-sep</code></td></tr><tr><td>Button - Toggle remaining time</td><td><code>.audio-player__duration</code></td></tr><tr><td>Button - Download audio</td><td><code>.audio-player__download</code></td></tr><tr><td>eyebrow (headphones + label)</td><td><code>.audio-player__eyebrow</code> + <code>.audio-player__eyebrow-label</code></td></tr><tr><td>Heading 2 (card)</td><td><code>.audio-player__heading</code></td></tr><tr><td>mini title / sub</td><td><code>.audio-player__title</code> / <code>.audio-player__sub</code></td></tr><tr><td>mini row wrappers</td><td><code>.audio-player__mini-top</code> / <code>.audio-player__mini-bottom</code> (<code>display: contents</code> on desktop)</td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma</th><th>CSS token</th><th>Role</th></tr></thead><tbody><tr><td>surface/primary</td><td><code>--ai-surface-primary</code></td><td>container bg</td></tr><tr><td>border/secondary</td><td><code>--ai-border-secondary</code></td><td>container border</td></tr><tr><td>surface/brand</td><td><code>--ai-surface-brand</code></td><td>play fill, scrubber fill, played bars</td></tr><tr><td>surface/contrast</td><td><code>--ai-surface-contrast</code></td><td>scrubber track, unplayed bars</td></tr><tr><td>text/primary</td><td><code>--ai-text-primary</code></td><td>heading, compact duration</td></tr><tr><td>text/secondary</td><td><code>--ai-text-secondary</code></td><td>current time, mini sub, grouped time</td></tr><tr><td>text/contrast</td><td><code>--ai-text-contrast</code></td><td>&quot;/&quot; separator</td></tr><tr><td>text/brand</td><td><code>--ai-text-brand</code></td><td>eyebrow label</td></tr><tr><td>icon/invert</td><td><code>--ai-icon-invert</code></td><td>play/pause glyph (on brand)</td></tr><tr><td>icon/secondary</td><td><code>--ai-icon-secondary</code></td><td>download glyph</td></tr><tr><td>icon/brand</td><td><code>--ai-icon-brand</code></td><td>eyebrow headphones</td></tr><tr><td>spacing 7/8/9/10</td><td><code>--ai-spacing-7/8/9/10</code></td><td>control box sizes 32/40/48/56</td></tr><tr><td>spacing 0-5/1/2/3/4/5/6</td><td><code>--ai-spacing-*</code></td><td>gaps, padding, track height (4), bar min-w (2)</td></tr><tr><td>radius/full, radius/lg</td><td><code>--ai-radius-full</code>, <code>--ai-radius-lg</code></td><td>pill controls, card corners</td></tr><tr><td>size/11, size/6</td><td><code>--ai-size-11</code>, <code>--ai-size-6</code></td><td>768 / 320 frame widths (→ max-width)</td></tr><tr><td>font fixed xxs/xs/sm/md</td><td><code>--ai-font-fixed-*</code></td><td>type ramp</td></tr><tr><td>font medium/regular/semibold/bold</td><td><code>--ai-font-*</code></td><td>weights</td></tr><tr><td>leading md/sm</td><td><code>--ai-leading-*</code></td><td>line heights</td></tr><tr><td>icon 16/20/24</td><td><code>--ai-icon-size-sm/md/lg</code></td><td>icon sizing</td></tr></tbody></table><h2 id="token-gaps-decisions" tabindex="-1">Token Gaps &amp; Decisions <a class="header-anchor" href="#token-gaps-decisions" aria-label="Permalink to &quot;Token Gaps &amp; Decisions&quot;">​</a></h2><ul><li><strong>Control box sizes (40/48/56/32px)</strong> — Figma left these unbound. Approved to use the exactly-matching spacing tokens (<code>--ai-spacing-8/9/10/7</code>).</li><li><strong>Card drop-shadow</strong> <code>0 0 10px rgba(0,0,0,0.05)</code> — no existing <code>--ai-shadow-*</code> matched; <strong>new token <code>--ai-shadow-card</code></strong> added to <code>css/tokens-shadows.css</code> (light + dark).</li><li><strong>Same-value token slips (normalised, approved):</strong><ul><li>Sticky <strong>desktop</strong> play + slider-fill used <code>--ai-surface-info</code>; every other variant used <code>--ai-surface-brand</code> (both <code>#2563eb</code>) → normalised to <code>--ai-surface-brand</code>.</li><li>Card <strong>mobile</strong> heading used <code>--ai-text-neutral</code>; desktop used <code>--ai-text-primary</code> (both <code>#212123</code>) → normalised to <code>--ai-text-primary</code>.</li></ul></li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Lucide icons: <code>play</code>, <code>pause</code>, <code>download</code>, <code>headphones</code> (exact matches).</li><li><strong>Mini text stack</strong> (<code>.audio-player__text</code>): user override — gap removed (Figma 2px) and title/sub <code>line-height</code> set to <code>--ai-leading-sm</code> (20px; Figma <code>--ai-leading-md</code> 24px) for a tighter two-line block.</li><li><strong>Icon sizes:</strong> download + headphones are <code>--ai-icon-size-sm</code> (16px) on all versions. The headphones eyebrow is 16px in Figma; the download icon is a <strong>user override</strong> (Figma binds it at 20px / <code>--ai-icon-size-md</code>). Play/pause glyph stays 20px (24px on the card-desktop 56px button).</li><li><code>letter-spacing: 0.48px</code> on the eyebrow label is an optical value (kept as px).</li><li>Width is <code>100% / max-width: --ai-size-11</code> rather than a fixed 768px so the component fills its article column and shrinks on mobile — the Figma fixed widths are the canvas frame sizes.</li><li>Hover: Figma defines no hover/pressed states. Added conventional, token-based affordances only — play → <code>--ai-surface-brand-dark</code>, download → <code>--ai-surface-secondary</code>.</li><li>The &quot;sticky&quot; positioning (dock-on-scroll) is a <em>usage</em> concern, not part of the component — the Figma &quot;Sticky Mini Player&quot; variant is just the bar chrome.</li></ul>',18)])])}const h=t(i,[["render",r]]);export{u as __pageData,h as default};
